// CreateTransaction handles fund transfers between accounts.
func (s *TransactionServer) CreateTransaction(ctx context.Context, req *CreateTransactionRequest) (*CreateTransactionResponse, error) {
	// Validate caller identity from mTLS peer info.
	if err := s.validatePeer(ctx); err != nil {
		return nil, err
	}

	// Input validation.
	if req.FromAccountId == "" || req.ToAccountId == "" {
		return nil, status.Error(codes.InvalidArgument, "from_account_id and to_account_id are required")
	}
	if req.AmountCents <= 0 {
		return nil, status.Error(codes.InvalidArgument, "amount_cents must be positive")
	}
	if req.Currency == "" {
		return nil, status.Error(codes.InvalidArgument, "currency is required")
	}
	if req.FromAccountId == req.ToAccountId {
		return nil, status.Error(codes.InvalidArgument, "cannot transfer to the same account")
	}
	if req.IdempotencyKey == "" {
		return nil, status.Error(codes.InvalidArgument, "idempotency_key is required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	// Idempotency check: return cached response if this key was already processed.
	if cached, ok := s.idempotencyCache[req.IdempotencyKey]; ok {
		log.Printf("Idempotency hit for key=%s, returning cached response", req.IdempotencyKey)
		return cached, nil
	}

	fromAcct, ok := s.accounts[req.FromAccountId]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "source account %s not found", req.FromAccountId)
	}
	toAcct, ok := s.accounts[req.ToAccountId]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "destination account %s not found", req.ToAccountId)
	}

	// Currency validation.
	if fromAcct.Currency != req.Currency || toAcct.Currency != req.Currency {
		return nil, status.Error(codes.FailedPrecondition, "currency mismatch between accounts and request")
	}

	// Sufficient funds check.
	if fromAcct.BalanceCents < req.AmountCents {
		return nil, status.Error(codes.FailedPrecondition, "insufficient funds")
	}

	// Execute transfer atomically (both under the same lock).
	fromAcct.BalanceCents -= req.AmountCents
	toAcct.BalanceCents += req.AmountCents

	txnID := uuid.New().String()
	now := time.Now().UTC()

	record := &TransactionRecord{
		ID:            txnID,
		FromAccountID: req.FromAccountId,
		ToAccountID:   req.ToAccountId,
		AmountCents:   req.AmountCents,
		Currency:      req.Currency,
		Status:        "COMPLETED",
		Timestamp:     now.UnixMilli(),
	}
	s.transactions[txnID] = record

	resp := &CreateTransactionResponse{
		TransactionId: txnID,
		Status:        "COMPLETED",
		Timestamp:     now.UnixMilli(),
	}

	// Cache the response for idempotency.
	s.idempotencyCache[req.IdempotencyKey] = resp

	log.Printf("Transaction %s: %s -> %s, amount=%d %s", txnID, req.FromAccountId, req.ToAccountId, req.AmountCents, req.Currency)
	return resp, nil
}

// GetBalance returns the current balance for an account.
func (s *TransactionServer) GetBalance(ctx context.Context, req *GetBalanceRequest) (*GetBalanceResponse, error) {
	// Validate caller identity from mTLS peer info.
	if err := s.validatePeer(ctx); err != nil {
		return nil, err
	}

	if req.AccountId == "" {
		return nil, status.Error(codes.InvalidArgument, "account_id is required")
	}

	s.mu.RLock()
	defer s.mu.RUnlock()

	acct, ok := s.accounts[req.AccountId]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "account %s not found", req.AccountId)
	}

	return &GetBalanceResponse{
		AccountId:    acct.ID,
		BalanceCents: acct.BalanceCents,
		Currency:     acct.Currency,
	}, nil
}

// validatePeer extracts mTLS peer certificate info and validates the caller is an
// authorized internal service. This replaces token-based auth with strong identity.
func (s *TransactionServer) validatePeer(ctx context.Context) error {
	p, ok := peer.FromContext(ctx)
	if !ok {
		return status.Error(codes.Unauthenticated, "no peer info available")
	}

	tlsInfo, ok := p.AuthInfo.(credentials.TLSInfo)
	if !ok {
		return status.Error(codes.Unauthenticated, "connection is not TLS-secured")
	}

	if len(tlsInfo.State.VerifiedChains) == 0 || len(tlsInfo.State.VerifiedChains[0]) == 0 {
		return status.Error(codes.Unauthenticated, "no verified client certificate")
	}

	clientCert := tlsInfo.State.VerifiedChains[0][0]
	cn := clientCert.Subject.CommonName

	// Only allow known internal service identities.
	allowedServices := map[string]bool{
		"payment-service":    true,
		"account-service":    true,
		"settlement-service": true,
		"audit-service":      true,
	}

	if !allowedServices[cn] {
		log.Printf("Rejected connection from unauthorized service CN=%s", cn)
		return status.Errorf(codes.PermissionDenied, "service %q is not authorized", cn)
	}

	log.Printf("Authenticated service: %s", cn)
	return nil
}

// authUnaryInterceptor is a gRPC unary interceptor that enforces per-RPC authorization
// based on the caller's mTLS identity and the method being invoked.
func authUnaryInterceptor(
	ctx context.Context,
	req interface{},
	info *grpc.UnaryServerInfo,
	handler grpc.UnaryHandler,
) (interface{}, error) {
	// Extract service identity from metadata or peer for audit logging.
	md, _ := metadata.FromIncomingContext(ctx)
	requestID := "unknown"
	if vals := md.Get("x-request-id"); len(vals) > 0 {
		requestID = vals[0]
	}

	// Method-level authorization: restrict which services can call which RPCs.
	p, ok := peer.FromContext(ctx)
	if !ok {
		return nil, status.Error(codes.Unauthenticated, "no peer info")
	}
	tlsInfo, ok := p.AuthInfo.(credentials.TLSInfo)
	if !ok {
		return nil, status.Error(codes.Unauthenticated, "no TLS info")
	}
	if len(tlsInfo.State.VerifiedChains) == 0 || len(tlsInfo.State.VerifiedChains[0]) == 0 {
		return nil, status.Error(codes.Unauthenticated, "no verified client certificate in interceptor")
	}

	callerCN := tlsInfo.State.VerifiedChains[0][0].Subject.CommonName

	// Define method-level access control.
	methodACL := map[string][]string{
		"/transaction.TransactionService/CreateTransaction": {"payment-service", "settlement-service"},
		"/transaction.TransactionService/GetBalance":        {"payment-service", "account-service", "audit-service", "settlement-service"},
	}

	if allowedCallers, exists := methodACL[info.FullMethod]; exists {
		authorized := false
		for _, allowed := range allowedCallers {
			if callerCN == allowed {
				authorized = true
				break
			}
		}
		if !authorized {
			log.Printf("AUTHZ DENIED: service=%s method=%s request_id=%s", callerCN, info.FullMethod, requestID)
			return nil, status.Errorf(codes.PermissionDenied, "service %q not authorized for %s", callerCN, info.FullMethod)
		}
	}

	start := time.Now()
	log.Printf("RPC START: method=%s caller=%s request_id=%s", info.FullMethod, callerCN, requestID)

	resp, err := handler(ctx, req)

	duration := time.Since(start)
	if err != nil {
		log.Printf("RPC ERROR: method=%s caller=%s request_id=%s duration=%v error=%v",
			info.FullMethod, callerCN, requestID, duration, err)
	} else {
		log.Printf("RPC OK: method=%s caller=%s request_id=%s duration=%v",
			info.FullMethod, callerCN, requestID, duration)
	}

	return resp, err
}

// loadTLSCredentials loads mTLS configuration for the server.
func loadTLSCredentials(certFile, keyFile, caFile string) (credentials.TransportCredentials, error) {
	// Load CA certificate to verify client certificates.
	caCert, err := os.ReadFile(caFile)
	if err != nil {
		return nil, fmt.Errorf("failed to read CA cert: %w", err)
	}

	certPool := x509.NewCertPool()
	if !certPool.AppendCertsFromPEM(caCert) {
		return nil, fmt.Errorf("failed to add CA cert to pool")
	}

	// Load server certificate and key.
	serverCert, err := tls.LoadX509KeyPair(certFile, keyFile)
	if err != nil {
		return nil, fmt.Errorf("failed to load server cert/key: %w", err)
	}

	config := &tls.Config{
		Certificates: []tls.Certificate{serverCert},
		ClientAuth:   tls.RequireAndVerifyClientCert, // Enforce mTLS
		ClientCAs:    certPool,
		MinVersion:   tls.VersionTLS13, // Require TLS 1.3
	}

	return credentials.NewTLS(config), nil
}

